const signalsRaw = $('Get Active Signals').first().json;
const signals = Array.isArray(signalsRaw) ? signalsRaw : [signalsRaw];
const pricesRaw = $('Get Binance Prices').first().json;
const prices = Array.isArray(pricesRaw) ? pricesRaw : [pricesRaw];
const priceMap = {};
prices.forEach(p => { if(p.symbol) priceMap[p.symbol] = parseFloat(p.price); });

const results = [];
const now = new Date().toISOString();

for (const s of signals) {
  if (!s.symbol || !['ACTIVE', 'TP1_HIT', 'TP2_HIT'].includes(s.status || 'ACTIVE')) continue;
  const cp = priceMap[s.symbol];
  if (!cp) continue;

  const entry = parseFloat(s.entry_price);
  const tp1 = parseFloat(s.tp1);
  const tp2 = parseFloat(s.tp2);
  const tp3 = parseFloat(s.tp3);
  const sl = parseFloat(s.sl);
  const isBuy = s.signal === 'STRONG BUY';

  const currentStatus = s.status || 'ACTIVE';
  let newStatus = currentStatus;
  let profitPct = isBuy ? ((cp - entry) / entry * 100) : ((entry - cp) / entry * 100);

  // === PROGRESSIVE TRAILING STOP LOGIC ===
  // ACTIVE    : Stop at original SL
  // TP1_HIT   : Trailing stop moves to ENTRY (breakeven). TSL profit locked at TP1.
  // TP2_HIT   : Trailing stop moves to TP1 level. TSL profit locked at TP2.
  // Priority  : TP3 > TP2 > TP1 > TSL > SL

  if (isBuy) {
    if (cp >= tp3) {
      newStatus = 'TP3_HIT';
    } else if (cp >= tp2 && (currentStatus === 'TP1_HIT' || currentStatus === 'ACTIVE')) {
      newStatus = 'TP2_HIT';
    } else if (cp >= tp1 && currentStatus === 'ACTIVE') {
      newStatus = 'TP1_HIT';
    } else if (currentStatus === 'TP2_HIT' && cp <= tp1) {
      // After TP2: trail at TP1 level. Profit locked at TP2.
      newStatus = 'TSL_HIT';
      profitPct = (tp2 - entry) / entry * 100;
    } else if (currentStatus === 'TP1_HIT' && cp <= entry) {
      // After TP1: trail at entry. Profit locked at TP1.
      newStatus = 'TSL_HIT';
      profitPct = (tp1 - entry) / entry * 100;
    } else if (currentStatus === 'ACTIVE' && cp <= sl) {
      newStatus = 'SL_HIT';
    }
  } else {
    if (cp <= tp3) {
      newStatus = 'TP3_HIT';
    } else if (cp <= tp2 && (currentStatus === 'TP1_HIT' || currentStatus === 'ACTIVE')) {
      newStatus = 'TP2_HIT';
    } else if (cp <= tp1 && currentStatus === 'ACTIVE') {
      newStatus = 'TP1_HIT';
    } else if (currentStatus === 'TP2_HIT' && cp >= tp1) {
      // After TP2: trail at TP1 level. Profit locked at TP2.
      newStatus = 'TSL_HIT';
      profitPct = (entry - tp2) / entry * 100;
    } else if (currentStatus === 'TP1_HIT' && cp >= entry) {
      // After TP1: trail at entry. Profit locked at TP1.
      newStatus = 'TSL_HIT';
      profitPct = (entry - tp1) / entry * 100;
    } else if (currentStatus === 'ACTIVE' && cp >= sl) {
      newStatus = 'SL_HIT';
    }
  }

  if (newStatus !== currentStatus) {
    const mins = s.sent_at ? Math.round((Date.now() - new Date(s.sent_at).getTime()) / 60000) : 0;
    const dur = mins >= 60 ? Math.floor(mins/60)+'h '+mins%60+'m' : mins+'m';
    results.push({ json: {
      id: s.id, symbol: s.symbol, signal: s.signal, signal_type: s.signal_type,
      entry_price: s.entry_price, tp1: s.tp1, tp2: s.tp2, tp3: s.tp3, sl: s.sl,
      score: s.score, status: newStatus, profit_pct: Math.round(profitPct*100)/100,
      hit_time: now, duration: dur, current_price: cp,
      hitTarget: newStatus.replace('_HIT',''), changed: true
    }});
  }
}
if (results.length === 0) return [{ json: { changed: false } }];
return results;

